#define NIL -1



//array

int key[N];

int parent[N];

int leftc[N];

int rightc[N];

//root

int root=NIL;

//function insert

void insert(int z){

  int x,y;



  y=NIL;

  x=root;



  while(x!=NIL){

    y=x;

    if(key[z]<key[x]) x=leftc[x];

    else x=rightc[x];

  }  



  parent[z]=y;



  if(y==NIL) root=z;



  else if(key[z]<key[y]) leftc[y]=z;



  else rightc[y]=z;





}



//function search

bool find(int now,int data){

  if(now==NIL) return false;

  if(data==key[now]) return true;

  if(data<key[now]) return find(leftc[now],data);

  else return find(rightc[now],data);

}



//print

void inorderprint(int now){

  if(now!=NIL){

    inorderprint(leftc[now]);

    printf(" %d",key[now]);

    inorderprint(rightc[now]);

  }

}



void preorderprint(int now){

  if(now!=NIL){

    printf(" %d",key[now]);

    preorderprint(leftc[now]);

    preorderprint(rightc[now]);

  }

}







