BST* insert(BST* root, int val) {

    if (root == NULL) return new BST(val);

    if (root->val > val) root->left = insert(root->left, val);

    else root->right = insert(root->right, val);

    return root;

}



bool find(BST* root, int val) {

    if (root == NULL) return false;

    if (root->val == val) return true;

    if (root->val > val) return find(root->left, val);

    else return find(root->right, val);

}



BST* minValNode(BST* node) {

    BST* current = node;

    while (current->left != NULL) current = current->left;

    return current;

}



BST* deleteNode(BST* root, int val) {

    if (root == NULL) return root;

    if (root->val > val) root->left = deleteNode(root->left, val);

    else if (root->val < val) root->right = deleteNode(root->right, val);

    else {

        if (root->left == NULL) {

            BST* temp = root->right;

            free(root);

            return temp;

        }

        else if (root->right == NULL) {

            BST* temp = root->left;

            free(root);

            return temp;

        }

        BST* temp = minValNode(root->right);

        root->val = temp->val;

        root->right = deleteNode(root->right, temp->val);

    }

    return root;

