struct RAQSB{

	ll N;

	ll sN;

	ll data[N_MAX];

	ll bucket[N_MAX];



	RAQSB(ll n){

		sN = (ll)sqrt(n) + 1;

		N = sN * sN;

		REP(i, N_MAX){

			data[i] = 0;

			bucket[i] = 0;

		}

